begin;
create schema if not exists ged;
create table if not exists ged.tenant_security_configuration (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, permission_mode varchar(20) not null default 'LEGACY' check (permission_mode in ('LEGACY','AUDIT_ONLY','ENFORCED')), changed_at timestamptz not null default (now() at time zone 'utc'), changed_by text null, change_reason text null, reg_status varchar(1) not null default 'A');
create index if not exists ix_tenant_security_configuration_tenant on ged.tenant_security_configuration(tenant_id, reg_status);
create table if not exists ged.permission_evaluation_log (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, user_id uuid not null, permission_code text not null, module text null, route text null, action text null, legacy_result boolean not null, real_result boolean not null, permission_mode varchar(20) not null, correlation_id text null, evaluated_at timestamptz not null default (now() at time zone 'utc'), reg_status varchar(1) not null default 'A');
create index if not exists ix_permission_evaluation_log_tenant_date on ged.permission_evaluation_log(tenant_id, evaluated_at desc);
create table if not exists ged.permission_configuration_history (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, old_permission_mode varchar(20), new_permission_mode varchar(20) not null, changed_at timestamptz not null default (now() at time zone 'utc'), changed_by text null, change_reason text not null, correlation_id text null, reg_status varchar(1) not null default 'A');
create table if not exists ged.user_identity_document (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, user_id uuid not null, document_type varchar(20) not null, document_search_hash text not null, document_encrypted text not null, last_four_digits varchar(4) not null, source varchar(40) not null, verified boolean not null default false, verified_at timestamptz null, created_at timestamptz not null default (now() at time zone 'utc'), created_by text null, updated_at timestamptz null, updated_by text null, reg_status varchar(1) not null default 'A');
create unique index if not exists ux_user_identity_document_active on ged.user_identity_document(tenant_id,user_id,document_type) where reg_status='A';
create index if not exists ix_user_identity_document_hash on ged.user_identity_document(tenant_id,document_type,document_search_hash);
create table if not exists ged.identity_migration_job (id uuid primary key default gen_random_uuid(), tenant_id uuid null, status varchar(30) not null, dry_run boolean not null default true, requested_by text null, requested_at timestamptz not null default (now() at time zone 'utc'), justification text not null, finished_at timestamptz null, report_json jsonb null, reg_status varchar(1) not null default 'A');
create table if not exists ged.identity_migration_item (id uuid primary key default gen_random_uuid(), job_id uuid not null, tenant_id uuid not null, user_id uuid not null, status varchar(30) not null, masked_document text null, message text null, created_at timestamptz not null default (now() at time zone 'utc'), reg_status varchar(1) not null default 'A');
create index if not exists ix_identity_migration_item_job on ged.identity_migration_item(job_id,status);
create table if not exists ged.worker_execution_status (id uuid primary key default gen_random_uuid(), tenant_id uuid null, worker_name text not null, enabled boolean not null default true, status varchar(30) not null default 'UNKNOWN', last_execution_at timestamptz null, last_success_at timestamptz null, next_execution_at timestamptz null, duration_ms integer null, items_processed integer null, items_failed integer null, message text null, schema_state varchar(30) null, active_configuration jsonb null, updated_at timestamptz not null default (now() at time zone 'utc'), reg_status varchar(1) not null default 'A');
create index if not exists ix_worker_execution_status_tenant on ged.worker_execution_status(tenant_id, worker_name);
create table if not exists ged.administration_alert (id uuid primary key default gen_random_uuid(), tenant_id uuid null, severity varchar(20) not null, title text not null, message text not null, guidance text null, source text null, created_at timestamptz not null default (now() at time zone 'utc'), acknowledged_at timestamptz null, acknowledged_by text null, reg_status varchar(1) not null default 'A');
create table if not exists ged.compliance_control (id uuid primary key default gen_random_uuid(), tenant_id uuid null, code text not null, title text not null, state varchar(30) not null, notes text null, updated_at timestamptz not null default (now() at time zone 'utc'), reg_status varchar(1) not null default 'A');
create table if not exists ged.compliance_evidence (id uuid primary key default gen_random_uuid(), control_id uuid not null, tenant_id uuid null, evidence_type text not null, safe_summary text not null, created_at timestamptz not null default (now() at time zone 'utc'), created_by text null, reg_status varchar(1) not null default 'A');
do $$ begin if to_regclass('ged.schema_migration_history') is not null then insert into ged.schema_migration_history(script_name, notes) values ('2026_07_administration_security_governance.sql','Estruturas aditivas para Administração, Segurança e Governança.') on conflict (script_name) do nothing; end if; end $$;
commit;
